const claudeItem = $input.first();
const originalItem = $('Code: Build Claude Request').first();

const claudeText = claudeItem.json.content?.[0]?.text || '';

// Parse delimited sections from Claude response
function extractSection(text, tag) {
  const openTag = `---${tag}---`;
  const closeTag = '---END---';
  const start = text.indexOf(openTag);
  if (start === -1) return '';
  const contentStart = start + openTag.length;
  const end = text.indexOf(closeTag, contentStart);
  if (end === -1) return '';
  return text.slice(contentStart, end).trim();
}

const geminiPrompt = extractSection(claudeText, 'GEMINI_PROMPT');
const headline = extractSection(claudeText, 'HEADLINE');
const supportingLine = extractSection(claudeText, 'SUPPORTING_LINE');
const caption = extractSection(claudeText, 'CAPTION');
const canvaSpec = extractSection(claudeText, 'CANVA_SPEC');

// Recover image from the earlier Code node (not lost to HTTP response)
const imageBase64 = originalItem.json.image_base64;
const imageMime = originalItem.json.image_mime;

if (!geminiPrompt) {
  throw new Error('Failed to parse Gemini prompt from Claude response. Raw: ' + claudeText.slice(0, 300));
}

if (!imageBase64) {
  throw new Error('Product image base64 is missing. Check form upload.');
}

const geminiPayload = {
  contents: [{
    parts: [
      { inlineData: { mimeType: imageMime, data: imageBase64 } },
      { text: geminiPrompt }
    ]
  }],
  generationConfig: {
    responseModalities: ['TEXT', 'IMAGE']
  }
};

return [{
  json: {
    product: originalItem.json.product,
    format: originalItem.json.format,
    vibe: originalItem.json.vibe,
    gemini_prompt: geminiPrompt,
    headline,
    supporting_line: supportingLine,
    caption,
    canva_spec: canvaSpec,
    gemini_payload: geminiPayload
  }
}];

const geminiItem = $input.first();
const briefItem = $('Code: Parse Brief + Build Gemini Request').first();

const parts = geminiItem.json.candidates?.[0]?.content?.parts || [];

let imageBase64 = '';
let imageMimeType = 'image/png';

for (const part of parts) {
  if (part.inlineData?.data) {
    imageBase64 = part.inlineData.data;
    imageMimeType = part.inlineData.mimeType || 'image/png';
    break;
  }
}

const result = {
  json: {
    product: briefItem.json.product,
    format: briefItem.json.format,
    vibe: briefItem.json.vibe,
    headline: briefItem.json.headline,
    supporting_line: briefItem.json.supporting_line,
    caption: briefItem.json.caption,
    canva_spec: briefItem.json.canva_spec,
    gemini_prompt: briefItem.json.gemini_prompt,
    has_image: imageBase64.length > 0,
    image_mime: imageMimeType
  }
};

if (imageBase64) {
  result.binary = {
    generated_image: {
      data: imageBase64,
      mimeType: imageMimeType,
      fileName: `dubery-content-${Date.now()}.png`,
      fileExtension: 'png'
    }
  };
}

return [result];
